const { ethers } = require('ethers');
const fs = require('fs');

class EthereumService {
  constructor() {
    this.provider = null;
    this.wallet = null;
    this.contract = null;
  }

  async initialize(providerUrl, privateKey) {
    try {
      this.provider = new ethers.providers.JsonRpcProvider(providerUrl);
      this.wallet = new ethers.Wallet(privateKey, this.provider);
      return true;
    } catch (error) {
      console.error('Initialization failed:', error);
      return false;
    }
  }

  async sendETH(toAddress, amount) {
    try {
      const tx = {
        to: toAddress,
        value: ethers.utils.parseEther(amount.toString())
      };

      const transaction = await this.wallet.sendTransaction(tx);
      await transaction.wait();
      return transaction;
    } catch (error) {
      console.error('Send ETH failed:', error);
      throw error;
    }
  }

  async interactWithContract(contractAddress, abi, functionName, args = []) {
    try {
      this.contract = new ethers.Contract(contractAddress, abi, this.wallet);
      const transaction = await this.contract[functionName](...args);
      await transaction.wait();
      return transaction;
    } catch (error) {
      console.error('Contract interaction failed:', error);
      throw error;
    }
  }

  async getBalance() {
    try {
      const balance = await this.wallet.getBalance();
      return ethers.utils.formatEther(balance);
    } catch (error) {
      console.error('Get balance failed:', error);
      throw error;
    }
  }

  async getTransactionCount() {
    try {
      return await this.wallet.getTransactionCount();
    } catch (error) {
      console.error('Get transaction count failed:', error);
      throw error;
    }
  }
}

